          <div><div class="k">Filtros</div><div class="v"><span class="pill">status: ${P}</span> <span class="pill">canal: ${M}</span></div><div class="subtitle">${A.trim()?`busca: “${A.trim()}”`:"sem termo de busca"}</div></div>
